const config = require('../config.js');
const { daysBetween } = require('../lib/dates.js');
const { allTickets, saveTickets } = require('../core/tickets.js');
const { allComments, saveComments } = require('../core/comments.js');
const { syncStats } = require('../core/stats.js');
const { logEvent } = require('../core/events.js');

// Destructive command. Dry-run by default: print the plan, mutate nothing.
// --apply performs the permanent removal. Empty plan: print 'total: 0', exit code 3.
function isStale(ticket) {
  if (ticket.status !== 'closed') return false;
  return daysBetween(ticket.updatedAt, config.referenceDate) > config.retentionDays;
}

function purgeStaleTicK(args) {
  const apply = args.includes('--apply');

  const tickets = allTickets();
  const comments = allComments();
  const purgeTickets = tickets.filter(isStale);
  const purgedIds = new Set(purgeTickets.map((t) => t.id));
  const purgeComments = comments.filter((c) => purgedIds.has(c.ticketId));

  const lines = [
    ...purgeTickets.map((t) => `plan: purge ticket ${t.id}`),
    ...purgeComments.map((c) => `plan: purge comment ${c.id}`),
  ];
  const count = purgeTickets.length + purgeComments.length;

  if (count === 0) {
    return { lines: ['total: 0'], exitCode: 3 };
  }

  if (!apply) {
    return [...lines, `total: ${count}`];
  }

  saveTickets(tickets.filter((t) => !purgedIds.has(t.id)));
  saveComments(comments.filter((c) => !purgedIds.has(c.ticketId)));
  syncStats();
  logEvent('purge', count);

  return [...lines, `applied: ${count}`];
}

module.exports = { purgeStaleTicK };

